import { Server, Socket } from 'socket.io';

interface PerSocketAudit { socketId: string; bytesTracked: number; emitCount: number; }

export class SocketLeakAudit {
  private audits = new WeakMap<Socket, PerSocketAudit>();
  private bySocketId = new Map<string, WeakRef<Socket>>();
  private registry = new FinalizationRegistry((socketId: string) => { this.bySocketId.delete(socketId); });

  attach(io: Server): void {
    io.on('connection', (socket: Socket) => {
      const audit: PerSocketAudit = { socketId: socket.id, bytesTracked: 0, emitCount: 0 };
      this.audits.set(socket, audit);
      this.bySocketId.set(socket.id, new WeakRef(socket));
      this.registry.register(socket, socket.id);

      const originalEmit = socket.emit.bind(socket);
      socket.emit = ((event: string, ...args: unknown[]) => {
        const size = JSON.stringify(args).length;
        audit.bytesTracked += size;
        audit.emitCount++;
        return originalEmit(event, ...args);
      }) as typeof socket.emit;
    });
  }

  snapshot(): PerSocketAudit[] {
    const result: PerSocketAudit[] = [];
    for (const ref of this.bySocketId.values()) {
      const socket = ref.deref();
      if (!socket) continue;
      const audit = this.audits.get(socket);
      if (audit) result.push({ ...audit });
    }
    return result;
  }
}

import { Socket, Server } from 'socket.io';
import { trace, context, SpanStatusCode, Span } from '@opentelemetry/api';

const tracer = trace.getTracer('socket.io');

export function instrumentTracing(io: Server): void {
  io.on('connection', (socket: Socket) => {
    socket.onAny((event, ...args) => {
      const span = tracer.startSpan(`ws.${event}`, {
        attributes: { 'socket.id': socket.id, 'user.id': (socket.data as { userId?: string }).userId ?? 'anon', 'event.argCount': args.length },
      });
      const ack = args[args.length - 1];
      if (typeof ack === 'function') {
        args[args.length - 1] = ((...ackArgs: unknown[]) => {
          span.setStatus({ code: SpanStatusCode.OK });
          span.end();
          return (ack as (...a: unknown[]) => unknown)(...ackArgs);
        });
      } else {
        setImmediate(() => { span.setStatus({ code: SpanStatusCode.OK }); span.end(); });
      }
      attachErrorSpan(socket, span);
    });
  });
}

function attachErrorSpan(socket: Socket, span: Span): void {
  socket.once('error', (err: Error) => {
    span.recordException(err);
    span.setStatus({ code: SpanStatusCode.ERROR, message: err.message });
    span.end();
  });
}

import { io, Socket } from 'socket.io-client';
import type { ServerToClientEvents, ClientToServerEvents } from './shared/events';

export type AppSocket = Socket<ServerToClientEvents, ClientToServerEvents>;

export function createClient(url: string, token: string): AppSocket {
  return io(url, { auth: { token }, withCredentials: true, transports: ['websocket'] });
}

export async function sendChatMessage(socket: AppSocket, text: string): Promise<{ id: string }> {
  return new Promise((resolve, reject) => {
    socket.timeout(5000).emit('chat:send', text, (err: Error | null, res?: { ok: true; id: string } | { ok: false; error: string }) => {
      if (err) return reject(err);
      if (!res || !res.ok) return reject(new Error(res?.error ?? 'UNKNOWN'));
      resolve({ id: res.id });
    });
  });
}

import { Server, Socket } from 'socket.io';

interface SignalingEvents {
  'webrtc:offer': (to: string, sdp: RTCSessionDescriptionInit) => void;
  'webrtc:answer': (to: string, sdp: RTCSessionDescriptionInit) => void;
  'webrtc:ice': (to: string, candidate: RTCIceCandidateInit) => void;
  'webrtc:peers': (peers: string[]) => void;
}

export function mountSignaling(io: Server): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId: string }).userId;

    socket.on('webrtc:join', async (roomId: string) => {
      await socket.join(`rtc:${roomId}`);
      const others = (await io.in(`rtc:${roomId}`).fetchSockets()).filter((s) => s.id !== socket.id).map((s) => s.id);
      socket.emit('webrtc:peers', others);
      socket.to(`rtc:${roomId}`).emit('webrtc:peer-joined', { peerId: socket.id, userId });
    });

    socket.on('webrtc:offer', (to: string, sdp: RTCSessionDescriptionInit) => {
      io.to(to).emit('webrtc:offer', { from: socket.id, sdp });
    });

    socket.on('webrtc:answer', (to: string, sdp: RTCSessionDescriptionInit) => {
      io.to(to).emit('webrtc:answer', { from: socket.id, sdp });
    });

    socket.on('webrtc:ice', (to: string, candidate: RTCIceCandidateInit) => {
      io.to(to).emit('webrtc:ice', { from: socket.id, candidate });
    });

    socket.on('disconnecting', () => {
      for (const room of socket.rooms) {
        if (!room.startsWith('rtc:')) continue;
        socket.to(room).emit('webrtc:peer-left', { peerId: socket.id });
      }
    });
  });
}

import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import { Schema, model } from 'mongoose';

export type Scope = 'read:users' | 'write:users' | 'read:orders' | 'write:orders';

interface ApiKey { _id: string; tenantId: string; hashedKey: string; scopes: Scope[]; createdAt: Date; lastUsedAt: Date | null; revokedAt: Date | null; }

const ApiKeySchema = new Schema<ApiKey>({
  tenantId: { type: String, required: true, index: true },
  hashedKey: { type: String, required: true, unique: true },
  scopes: { type: [String], default: [] },
  createdAt: { type: Date, default: Date.now },
  lastUsedAt: Date,
  revokedAt: Date,
});
export const ApiKeyModel = model<ApiKey>('ApiKey', ApiKeySchema);

export function hashKey(raw: string): string { return crypto.createHash('sha256').update(raw).digest('hex'); }

export function generateApiKey(): { raw: string; hashed: string } {
  const raw = `sk_${crypto.randomBytes(24).toString('base64url')}`;
  return { raw, hashed: hashKey(raw) };
}

export function requireScope(...needed: Scope[]) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const header = req.header('Authorization');
    const raw = header?.startsWith('Bearer ') ? header.slice(7) : null;
    if (!raw) { res.status(401).json({ error: 'NO_KEY' }); return; }
    const key = await ApiKeyModel.findOne({ hashedKey: hashKey(raw), revokedAt: null }).lean<ApiKey | null>();
    if (!key) { res.status(401).json({ error: 'INVALID_KEY' }); return; }
    if (!needed.every((s) => key.scopes.includes(s))) { res.status(403).json({ error: 'MISSING_SCOPE', need: needed, have: key.scopes }); return; }
    (req as Request & { tenantId: string; apiKeyId: string }).tenantId = key.tenantId;
    (req as Request & { tenantId: string; apiKeyId: string }).apiKeyId = key._id;
    void ApiKeyModel.updateOne({ _id: key._id }, { $set: { lastUsedAt: new Date() } });
    next();
  };
}

import https from 'https';
import tls from 'tls';
import fs from 'fs';
import crypto from 'crypto';

export interface MtlsOptions { clientCertPath: string; clientKeyPath: string; caCertPath: string; pinnedFingerprint: string; }

export function createMtlsAgent(opts: MtlsOptions): https.Agent {
  return new https.Agent({
    cert: fs.readFileSync(opts.clientCertPath),
    key: fs.readFileSync(opts.clientKeyPath),
    ca: fs.readFileSync(opts.caCertPath),
    rejectUnauthorized: true,
    checkServerIdentity: (host, peerCert: tls.PeerCertificate): Error | undefined => {
      const defaultErr = tls.checkServerIdentity(host, peerCert);
      if (defaultErr) return defaultErr;
      const fingerprint = crypto.createHash('sha256').update(peerCert.raw).digest('hex').toLowerCase();
      if (fingerprint !== opts.pinnedFingerprint.toLowerCase()) {
        return new Error(`CERT_PIN_MISMATCH: got ${fingerprint}, expected ${opts.pinnedFingerprint}`);
      }
      return undefined;
    },
  });
}

import crypto from 'crypto';

export function generateToken(byteLength = 16): string {
  if (byteLength < 8) throw new Error('TOKEN_TOO_SHORT');
  return crypto.randomBytes(byteLength).toString('base64url');
}

export function generateUuidV7(): string {
  const ms = BigInt(Date.now());
  const bytes = crypto.randomBytes(16);
  bytes[0] = Number((ms >> 40n) & 0xffn);
  bytes[1] = Number((ms >> 32n) & 0xffn);
  bytes[2] = Number((ms >> 24n) & 0xffn);
  bytes[3] = Number((ms >> 16n) & 0xffn);
  bytes[4] = Number((ms >> 8n) & 0xffn);
  bytes[5] = Number(ms & 0xffn);
  bytes[6] = (bytes[6] & 0x0f) | 0x70;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;
  const hex = bytes.toString('hex');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
}

const CC_REGEX = /\b(?:\d[ -]*?){13,19}\b/g;
const JWT_REGEX = /eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g;
const BEARER_REGEX = /(Bearer\s+)[A-Za-z0-9._~+\/=-]+/gi;
const REDACT_KEYS = new Set(['password', 'passwordhash', 'token', 'authorization', 'cookie', 'apikey', 'secret', 'creditcard', 'cvv', 'ssn']);

export function redactString(input: string): string {
  return input
    .replace(BEARER_REGEX, '$1[REDACTED]')
    .replace(JWT_REGEX, '[REDACTED_JWT]')
    .replace(CC_REGEX, '[REDACTED_CARD]');
}

export function redactObject(value: unknown, depth = 0): unknown {
  if (depth > 8 || value === null || typeof value !== 'object') return typeof value === 'string' ? redactString(value) : value;
  if (Array.isArray(value)) return value.map((v) => redactObject(v, depth + 1));
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(value)) {
    if (REDACT_KEYS.has(k.toLowerCase())) out[k] = '[REDACTED]';
    else out[k] = redactObject(v, depth + 1);
  }
  return out;
}

export class SafeLogger {
  info(msg: string, ctx: Record<string, unknown> = {}): void { console.log(JSON.stringify({ level: 'info', msg, ...(redactObject(ctx) as Record<string, unknown>) })); }
  error(msg: string, ctx: Record<string, unknown> = {}): void { console.error(JSON.stringify({ level: 'error', msg, ...(redactObject(ctx) as Record<string, unknown>) })); }
}

interface WebhookDelivery { eventId: string; subscriberId: string; url: string; payload: unknown; attempt: number; }
interface DeliveryQueue { enqueue(d: WebhookDelivery, delayMs?: number): Promise<void>; }

export class WebhookDispatcher {
  constructor(private readonly queue: DeliveryQueue, private readonly breaker: { allow(subscriberId: string): boolean; onSuccess(subscriberId: string): void; onFailure(subscriberId: string): void }) {}

  private readonly maxAttempts = 8;
  private readonly backoffMs = (attempt: number): number => Math.min(60_000 * 2 ** Math.min(attempt, 8), 15 * 60_000);

  async deliver(delivery: WebhookDelivery): Promise<void> {
    if (!this.breaker.allow(delivery.subscriberId)) {
      await this.queue.enqueue(delivery, this.backoffMs(delivery.attempt));
      return;
    }
    try {
      const res = await fetch(delivery.url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-Event-Id': delivery.eventId },
        body: JSON.stringify(delivery.payload),
        signal: AbortSignal.timeout(10_000),
      });
      if (res.status >= 200 && res.status < 300) { this.breaker.onSuccess(delivery.subscriberId); return; }
      if (res.status >= 400 && res.status < 500 && res.status !== 408 && res.status !== 429) {
        this.breaker.onSuccess(delivery.subscriberId);
        return;
      }
      throw new Error(`HTTP_${res.status}`);
    } catch {
      this.breaker.onFailure(delivery.subscriberId);
      if (delivery.attempt < this.maxAttempts) await this.queue.enqueue({ ...delivery, attempt: delivery.attempt + 1 }, this.backoffMs(delivery.attempt + 1));
    }
  }
}

import { AnchorHTMLAttributes, ReactNode } from 'react';

const SAFE_SCHEMES = ['http:', 'https:', 'mailto:', 'tel:'];

function isSafeUrl(rawHref: string): boolean {
  try {
    const url = new URL(rawHref, 'https://example.com');
    if (rawHref.startsWith('/')) return true;
    return SAFE_SCHEMES.includes(url.protocol);
  } catch { return false; }
}

interface SafeLinkProps extends Omit<AnchorHTMLAttributes<HTMLAnchorElement>, 'href' | 'rel' | 'target'> { href: string; children: ReactNode; }

export function SafeLink({ href, children, ...rest }: SafeLinkProps): JSX.Element {
  if (!isSafeUrl(href)) return <span {...rest}>{children}</span>;
  const isExternal = /^https?:/i.test(href);
  return (
    <a href={href} target={isExternal ? '_blank' : undefined} rel={isExternal ? 'noopener noreferrer nofollow' : undefined} {...rest}>
      {children}
    </a>
  );
}

import { createContext, useContext, useRef, ReactNode, useCallback, useSyncExternalStore } from 'react';

type Listener<T> = (state: T) => void;
interface ScopedStore<T> { get: () => T; set: (updater: (s: T) => T) => void; subscribe: (l: Listener<T>) => () => void; }

function createScopedStore<T>(initial: T): ScopedStore<T> {
  let state = initial;
  const listeners = new Set<Listener<T>>();
  return {
    get: () => state,
    set: (updater) => { state = updater(state); listeners.forEach((l) => l(state)); },
    subscribe: (l) => { listeners.add(l); return () => { listeners.delete(l); }; },
  };
}

export function createScopedContext<T>(defaultInitial: T) {
  const Ctx = createContext<ScopedStore<T> | null>(null);

  function Provider({ children, initial }: { children: ReactNode; initial?: T }): JSX.Element {
    const ref = useRef<ScopedStore<T> | null>(null);
    if (!ref.current) ref.current = createScopedStore(initial ?? defaultInitial);
    return <Ctx.Provider value={ref.current}>{children}</Ctx.Provider>;
  }

  function useSelector<S>(selector: (s: T) => S): S {
    const store = useContext(Ctx);
    if (!store) throw new Error('No scoped provider');
    const get = useCallback(() => selector(store.get()), [store, selector]);
    return useSyncExternalStore(store.subscribe, get, get);
  }

  function useSet(): ScopedStore<T>['set'] {
    const store = useContext(Ctx);
    if (!store) throw new Error('No scoped provider');
    return store.set;
  }

  return { Provider, useSelector, useSet };
}

import { useReducer, useMemo } from 'react';

export interface Item { id: string; name: string; price: number; }

interface CatalogState { items: Item[]; }

type Action = { type: 'SET'; items: Item[] } | { type: 'ADD'; item: Item } | { type: 'REMOVE'; id: string };

function reducer(state: CatalogState, action: Action): CatalogState {
  switch (action.type) {
    case 'SET': return { items: action.items };
    case 'ADD': return { items: [...state.items, action.item] };
    case 'REMOVE': return { items: state.items.filter((i) => i.id !== action.id) };
  }
}

export function useCatalog() {
  const [state, dispatch] = useReducer(reducer, { items: [] });
  const byId = useMemo(() => new Map(state.items.map((i) => [i.id, i] as const)), [state.items]);
  const totalPrice = useMemo(() => state.items.reduce((sum, i) => sum + i.price, 0), [state.items]);
  return { items: state.items, byId, totalPrice, dispatch };
}

import { useEffect, useRef, ReactNode } from 'react';
import { createPortal } from 'react-dom';

const FOCUSABLE_SELECTOR = 'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';

interface ModalProps { open: boolean; onClose: () => void; children: ReactNode; labelledBy?: string; }

export function AccessibleModal({ open, onClose, children, labelledBy }: ModalProps): JSX.Element | null {
  const panelRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    if (!open) return;
    previousFocusRef.current = document.activeElement as HTMLElement | null;
    const panel = panelRef.current;
    if (!panel) return;

    const focusables = panel.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR);
    focusables[0]?.focus();

    const onKey = (e: KeyboardEvent): void => {
      if (e.key === 'Escape') { onClose(); return; }
      if (e.key !== 'Tab') return;
      const list = panel.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR);
      if (list.length === 0) { e.preventDefault(); return; }
      const first = list[0];
      const last = list[list.length - 1];
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
    };
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('keydown', onKey);
      previousFocusRef.current?.focus();
    };
  }, [open, onClose]);

  if (!open) return null;
  return createPortal(
    <div role="dialog" aria-modal="true" aria-labelledby={labelledBy} className="fixed inset-0 bg-black/50 flex items-center justify-center">
      <div ref={panelRef} className="bg-white rounded-lg p-6 max-w-md w-full">{children}</div>
    </div>,
    document.body,
  );
}

import { useEffect, useState } from 'react';

interface BroadcastSource { on(event: string, handler: (data: unknown) => void): void; off(event: string, handler: (data: unknown) => void): void; }

export function useBroadcast<T>(source: BroadcastSource, event: string): T | null {
  const [value, setValue] = useState<T | null>(null);
  useEffect(() => {
    const handler = (data: unknown): void => setValue(data as T);
    source.on(event, handler);
    return () => source.off(event, handler);
  }, [source, event]);
  return value;
}

import { Canvas } from '@react-three/fiber';
import { DirectionalLight, PCFSoftShadowMap } from 'three';
import { useRef, useEffect } from 'react';

export function ShadowScene({ children }: { children: React.ReactNode }): JSX.Element {
  const lightRef = useRef<DirectionalLight>(null);

  useEffect(() => {
    if (!lightRef.current) return;
    const light = lightRef.current;
    light.shadow.mapSize.set(2048, 2048);
    light.shadow.camera.near = 0.1;
    light.shadow.camera.far = 50;
    light.shadow.camera.left = -15;
    light.shadow.camera.right = 15;
    light.shadow.camera.top = 15;
    light.shadow.camera.bottom = -15;
    light.shadow.bias = -0.0005;
    light.shadow.normalBias = 0.05;
    light.shadow.camera.updateProjectionMatrix();
  }, []);

  return (
    <Canvas shadows={{ type: PCFSoftShadowMap }} camera={{ position: [10, 8, 12], fov: 45 }}>
      <ambientLight intensity={0.3} />
      <directionalLight ref={lightRef} position={[10, 15, 5]} intensity={1.2} castShadow />
      {children}
    </Canvas>
  );
}

import { Mesh, InstancedMesh, Raycaster, Vector2, Object3D, Matrix4 } from 'three';

export interface PickResult { instanceId: number; mesh: InstancedMesh; point: { x: number; y: number; z: number }; }

export function pickFromInstanced(raycaster: Raycaster, target: InstancedMesh): PickResult | null {
  const intersections = raycaster.intersectObject(target, false);
  const hit = intersections[0];
  if (!hit || hit.instanceId === undefined) return null;
  return { instanceId: hit.instanceId, mesh: target, point: { x: hit.point.x, y: hit.point.y, z: hit.point.z } };
}

export function getInstanceMatrix(mesh: InstancedMesh, instanceId: number): Matrix4 {
  const m = new Matrix4();
  mesh.getMatrixAt(instanceId, m);
  return m;
}

export function attachClickPicker(
  canvas: HTMLCanvasElement,
  raycaster: Raycaster,
  camera: import('three').Camera,
  meshes: ReadonlyArray<InstancedMesh>,
  onPick: (result: PickResult | null) => void,
): () => void {
  const pointer = new Vector2();
  const handler = (event: PointerEvent): void => {
    const rect = canvas.getBoundingClientRect();
    pointer.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    pointer.y = -(((event.clientY - rect.top) / rect.height) * 2 - 1);
    raycaster.setFromCamera(pointer, camera);
    for (const mesh of meshes) {
      const result = pickFromInstanced(raycaster, mesh);
      if (result) { onPick(result); return; }
    }
    onPick(null);
  };
  canvas.addEventListener('pointerdown', handler);
  return () => canvas.removeEventListener('pointerdown', handler);
}

