import { PMREMGenerator } from 'three';

export function PbrScene({ children, envPreset = 'sunset' }: { children: React.ReactNode; envPreset?: 'sunset' | 'dawn' | 'night' | 'warehouse' | 'forest' | 'apartment' | 'studio' | 'city' | 'park' | 'lobby' }): JSX.Element {
