function useCustomEnv(hdrUrl: string): void {
  const { gl, scene } = useThree();
  useEffect(() => {
    let cancelled = false;
    void import('three/examples/jsm/loaders/RGBELoader.js').then(({ RGBELoader }) => {
      if (cancelled) return;
      const pmrem = new PMREMGenerator(gl);
      pmrem.compileEquirectangularShader();
      new RGBELoader().load(hdrUrl, (texture) => {
        if (cancelled) return;
        const envMap = pmrem.fromEquirectangular(texture).texture;
        scene.environment = envMap;
        texture.dispose();
        pmrem.dispose();
      });
    });
    return () => { cancelled = true; };
  }, [gl, scene, hdrUrl]);
}

import { useState } from 'react';
import { ThreeEvent } from '@react-three/fiber';

interface HoverableMeshProps { position: [number, number, number]; label: string; }

export function HoverableMesh({ position, label }: HoverableMeshProps): JSX.Element {
  const [hovered, setHovered] = useState(false);

  const onOver = (e: ThreeEvent<PointerEvent>): void => { e.stopPropagation(); setHovered(true); document.body.style.cursor = 'pointer'; };
  const onOut = (): void => { setHovered(false); document.body.style.cursor = 'auto'; };

  return (
    <mesh position={position} onPointerOver={onOver} onPointerOut={onOut}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color={hovered ? 'tomato' : 'royalblue'} />
    </mesh>
  );
}

import { AsyncLocalStorage } from 'async_hooks';
import { Request, Response, NextFunction } from 'express';

export interface RequestScope { requestId: string; method: string; path: string; userId?: string; startedAt: number; }

export const scope = new AsyncLocalStorage<RequestScope>();

export function scopeMiddleware(req: Request, _res: Response, next: NextFunction): void {
  const ctx: RequestScope = { requestId: req.header('X-Request-Id') ?? crypto.randomUUID(), method: req.method, path: req.path, userId: (req as Request & { userId?: string }).userId, startedAt: Date.now() };
  scope.run(ctx, () => next());
}

export function currentScope(): RequestScope | undefined { return scope.getStore(); }

export function enrichedError(err: Error): Error & { context?: RequestScope } {
  const ctx = currentScope();
  (err as Error & { context?: RequestScope }).context = ctx;
  return err as Error & { context?: RequestScope };
}

import crypto from 'crypto';

import type { Redis } from 'ioredis';

export interface Recommendation { id: string; title: string; score: number; }

export class RecommendationService {
  constructor(private readonly redis: Redis, private readonly upstream: (userId: string) => Promise<Recommendation[]>) {}

  async forUser(userId: string): Promise<{ items: Recommendation[]; stale: boolean }> {
    try {
      const items = await Promise.race([
        this.upstream(userId),
        new Promise<Recommendation[]>((_, reject) => setTimeout(() => reject(new Error('TIMEOUT')), 500)),
      ]);
      await this.redis.set(`recs:${userId}`, JSON.stringify(items), 'EX', 3600);
      return { items, stale: false };
    } catch {
      const cached = await this.redis.get(`recs:${userId}`);
      if (cached) return { items: JSON.parse(cached) as Recommendation[], stale: true };
      return { items: [], stale: true };
    }
  }
}

import { Schema, model, ClientSession } from 'mongoose';
import mongoose from 'mongoose';
import crypto from 'crypto';

interface OutboxEvent {
  _id: string;
  aggregateType: string;
  aggregateId: string;
  eventType: string;
  payload: unknown;
  createdAt: Date;
  publishedAt: Date | null;
  lockedAt?: Date | null;
  lockId?: string | null;
}

const OutboxSchema = new Schema<OutboxEvent>({
  aggregateType: { type: String, required: true },
  aggregateId: { type: String, required: true },
  eventType: { type: String, required: true },
  payload: Schema.Types.Mixed,
  createdAt: { type: Date, default: Date.now },
  publishedAt: { type: Date, default: null, index: true },
  lockedAt: { type: Date, default: null },
  lockId: { type: String, default: null },
});
OutboxSchema.index({ publishedAt: 1, lockedAt: 1, createdAt: 1 });
export const OutboxModel = model<OutboxEvent>('OutboxEvent', OutboxSchema);

export async function appendOutbox(session: ClientSession, event: Pick<OutboxEvent, 'aggregateType' | 'aggregateId' | 'eventType' | 'payload'>): Promise<void> {
  await OutboxModel.create([{ ...event, createdAt: new Date() }], { session });
}

export interface EventPublisher { publish(event: OutboxEvent): Promise<void>; }

export async function drainOutbox(publisher: EventPublisher, batchSize = 100): Promise<number> {
  let published = 0;
  for (let i = 0; i < batchSize; i++) {
    const lockId = crypto.randomUUID();
    const staleBefore = new Date(Date.now() - 60_000);
    const event = await OutboxModel.findOneAndUpdate(
      { publishedAt: null, $or: [{ lockedAt: null }, { lockedAt: { $lt: staleBefore } }] },
      { $set: { lockedAt: new Date(), lockId } },
      { sort: { createdAt: 1 }, new: true, lean: true },
    );
    if (!event) break;
    try {
      await publisher.publish(event);
      await OutboxModel.updateOne({ _id: event._id, lockId }, { $set: { publishedAt: new Date() }, $unset: { lockedAt: 1, lockId: 1 } });
      published++;
    } catch (err) {
      await OutboxModel.updateOne({ _id: event._id, lockId }, { $unset: { lockedAt: 1, lockId: 1 } });
      console.error('[outbox] publish failed', event._id, err);
      break;
    }
  }
  return published;
}

export async function createOrderWithEvent(orderInput: { userId: string; items: Array<{ sku: string; qty: number }> }): Promise<string> {
  const session = await mongoose.startSession();
  try {
    let orderId = '';
    await session.withTransaction(async () => {
      const order = await mongoose.model('Order').create([{ ...orderInput }], { session });
      orderId = order[0]._id.toString();
      await appendOutbox(session, { aggregateType: 'Order', aggregateId: orderId, eventType: 'order.created', payload: { orderId, ...orderInput } });
    });
    return orderId;
  } finally { await session.endSession(); }
}

import mongoose, { ClientSession } from 'mongoose';

export class UnitOfWork {
  private session: ClientSession | null = null;
  async begin(): Promise<void> { this.session = await mongoose.startSession(); this.session.startTransaction(); }
  async commit(): Promise<void> { if (!this.session) throw new Error('NO_SESSION'); await this.session.commitTransaction(); await this.session.endSession(); this.session = null; }
  async rollback(): Promise<void> { if (!this.session) return; try { await this.session.abortTransaction(); } catch {} finally { await this.session.endSession(); this.session = null; } }
  get current(): ClientSession { if (!this.session) throw new Error('NO_SESSION'); return this.session; }
}

export async function withUnitOfWork<T>(work: (uow: UnitOfWork) => Promise<T>): Promise<T> {
  const uow = new UnitOfWork();
  await uow.begin();
  try { const result = await work(uow); await uow.commit(); return result; }
  catch (e) { await uow.rollback(); throw e; }
}

