import v8 from 'v8';
import fs from 'fs';
import path from 'path';
import { Request, Response, NextFunction } from 'express';

export interface HeapSnapshotter { capture(): Promise<{ path: string; sizeBytes: number }>; }

export function createHeapSnapshotter(dir: string): HeapSnapshotter {
  return {
    async capture() {
      await fs.promises.mkdir(dir, { recursive: true });
      const filename = path.join(dir, `heap-${Date.now()}.heapsnapshot`);
      await new Promise<void>((resolve, reject) => {
        const stream = v8.getHeapSnapshot();
        const out = fs.createWriteStream(filename);
        stream.pipe(out);
        out.on('finish', resolve);
        out.on('error', reject);
        stream.on('error', reject);
      });
      const stat = await fs.promises.stat(filename);
      return { path: filename, sizeBytes: stat.size };
    },
  };
}

export function requireAdminMiddleware(adminToken: string) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const token = req.header('X-Admin-Token');
    if (token !== adminToken) { res.status(403).json({ error: 'FORBIDDEN' }); return; }
    next();
  };
}

