import { useCallback, useMemo, useRef } from 'react';
import { VariableSizeGrid, GridChildComponentProps } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';

export interface ColumnDef { key: string; label: string; width: number; }

export interface Row { id: string; values: Record<string, string | number>; }

export interface DataGridProps { columns: ReadonlyArray<ColumnDef>; rows: ReadonlyArray<Row>; rowHeight?: number; }

export function DataGrid({ columns, rows, rowHeight = 36 }: DataGridProps): JSX.Element {
  const gridRef = useRef<VariableSizeGrid>(null);
  const colWidths = useMemo(() => columns.map((c) => c.width), [columns]);
  const getColumnWidth = useCallback((i: number) => colWidths[i] ?? 100, [colWidths]);
  const getRowHeight = useCallback(() => rowHeight, [rowHeight]);

  const Cell = useCallback(({ columnIndex, rowIndex, style }: GridChildComponentProps): JSX.Element => {
    const col = columns[columnIndex];
    const row = rows[rowIndex];
    return (
      <div style={style} className="px-2 py-1 border-b border-r text-sm truncate">
        {String(row.values[col.key] ?? '')}
      </div>
    );
  }, [columns, rows]);

  return (
    <AutoSizer>{({ width, height }) => (
      <VariableSizeGrid ref={gridRef} columnCount={columns.length} columnWidth={getColumnWidth} height={height} rowCount={rows.length} rowHeight={getRowHeight} width={width}>
        {Cell}
      </VariableSizeGrid>
    )}</AutoSizer>
  );
}

