import { Schema, model } from 'mongoose';

interface Lease { _id: string; holder: string; expiresAt: Date; updatedAt: Date; }

const LeaseSchema = new Schema<Lease>({
  _id: { type: String },
  holder: { type: String, required: true },
  expiresAt: { type: Date, required: true },
  updatedAt: { type: Date, default: Date.now },
});
export const LeaseModel = model<Lease>('Lease', LeaseSchema);

export class Leader {
  private interval: ReturnType<typeof setInterval> | null = null;
  constructor(private readonly name: string, private readonly instanceId: string, private readonly leaseMs: number) {}

  async tryAcquire(): Promise<boolean> {
    const now = Date.now();
    const expires = new Date(now + this.leaseMs);
    try {
      await LeaseModel.updateOne(
        { _id: this.name, $or: [{ expiresAt: { $lt: new Date(now) } }, { holder: this.instanceId }] },
        { $set: { holder: this.instanceId, expiresAt: expires, updatedAt: new Date(now) } },
        { upsert: true },
      );
      const current = await LeaseModel.findById(this.name).lean<Lease | null>();
      return current?.holder === this.instanceId;
    } catch (err) {
      if ((err as { code?: number }).code === 11000) return false;
      throw err;
    }
  }

  async startHeartbeat(): Promise<void> {
    this.interval = setInterval(async () => { await this.tryAcquire(); }, this.leaseMs / 3);
  }

  async release(): Promise<void> {
    if (this.interval) { clearInterval(this.interval); this.interval = null; }
    await LeaseModel.deleteOne({ _id: this.name, holder: this.instanceId });
  }
}

export type RowFromHeaders<H extends ReadonlyArray<string>> = { [K in H[number]]: string };

export function parseCsv<const H extends ReadonlyArray<string>>(text: string, headers: H, delimiter = ','): Array<RowFromHeaders<H>> {
  const lines = text.split(/\r?\n/).filter((l) => l.length > 0);
  return lines.map((line) => {
    const cells = parseLine(line, delimiter);
    const row = {} as RowFromHeaders<H>;
    for (let i = 0; i < headers.length; i++) {
      (row as Record<string, string>)[headers[i]] = cells[i] ?? '';
    }
    return row;
  });
}

function parseLine(line: string, delimiter: string): string[] {
  const cells: string[] = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (inQuotes) {
      if (ch === '"' && line[i + 1] === '"') { current += '"'; i++; }
      else if (ch === '"') inQuotes = false;
      else current += ch;
    } else {
      if (ch === '"') inQuotes = true;
      else if (ch === delimiter) { cells.push(current); current = ''; }
      else current += ch;
    }
  }
  cells.push(current);
  return cells;
}

