import { CompactEncrypt, jwtDecrypt, importJWK, generateKeyPair, exportJWK } from 'jose';

export interface SensitiveClaims { sub: string; tempApiKey: string; scope: string[]; }

export class JweTokenService {
  constructor(private readonly privateKey: import('crypto').KeyLike, private readonly publicKey: import('crypto').KeyLike) {}

  static async generate(): Promise<JweTokenService> {
    const { privateKey, publicKey } = await generateKeyPair('RSA-OAEP-256', { extractable: false });
    return new JweTokenService(privateKey, publicKey);
  }

  async encrypt(claims: SensitiveClaims, expiresIn = '1h'): Promise<string> {
    const payload = new TextEncoder().encode(JSON.stringify({ ...claims, exp: Math.floor(Date.now() / 1000) + 3600 }));
    return new CompactEncrypt(payload).setProtectedHeader({ alg: 'RSA-OAEP-256', enc: 'A256GCM' }).encrypt(this.publicKey);
  }

  async decrypt(token: string): Promise<SensitiveClaims & { exp: number }> {
    const { payload } = await jwtDecrypt(token, this.privateKey, { keyManagementAlgorithms: ['RSA-OAEP-256'], contentEncryptionAlgorithms: ['A256GCM'] });
    return payload as unknown as SensitiveClaims & { exp: number };
  }
}

import { Request, Response } from 'express';
import path from 'path';
import fs from 'fs/promises';

export function safeFileDownload(baseDir: string) {
  const resolvedBase = path.resolve(baseDir) + path.sep;
  return async (req: Request, res: Response): Promise<void> => {
    const requested = req.params.filename;
    if (!requested || typeof requested !== 'string') { res.status(400).json({ error: 'NO_FILENAME' }); return; }
    if (requested.includes('\0')) { res.status(400).json({ error: 'INVALID' }); return; }
    const targetPath = path.resolve(baseDir, requested);
    if (!targetPath.startsWith(resolvedBase)) { res.status(403).json({ error: 'FORBIDDEN' }); return; }
    try {
      const stat = await fs.stat(targetPath);
      if (!stat.isFile()) { res.status(404).json({ error: 'NOT_FILE' }); return; }
      res.sendFile(targetPath);
    } catch { res.status(404).json({ error: 'NOT_FOUND' }); }
  };
}

import { useEffect, useSyncExternalStore } from 'react';
import { createPortal } from 'react-dom';

interface Toast { id: string; level: 'info' | 'success' | 'error'; message: string; expiresAt: number; }

let toasts: Toast[] = [];
const listeners = new Set<() => void>();

function notify(): void { listeners.forEach((l) => l()); }
function subscribe(l: () => void): () => void { listeners.add(l); return () => { listeners.delete(l); }; }
function getSnapshot(): Toast[] { return toasts; }

export function pushToast(level: Toast['level'], message: string, durationMs = 4000): void {
  const id = crypto.randomUUID();
  toasts = [...toasts, { id, level, message, expiresAt: Date.now() + durationMs }];
  notify();
  setTimeout(() => { toasts = toasts.filter((t) => t.id !== id); notify(); }, durationMs);
}

export function ToastContainer(): JSX.Element | null {
  const list = useSyncExternalStore(subscribe, getSnapshot, getSnapshot);
  if (typeof document === 'undefined') return null;
  return createPortal(
    <div className="fixed top-4 right-4 z-50 space-y-2">
      {list.map((t) => (
        <div key={t.id} className={`px-4 py-2 rounded shadow ${t.level === 'error' ? 'bg-red-600 text-white' : t.level === 'success' ? 'bg-green-600 text-white' : 'bg-gray-800 text-white'}`}>{t.message}</div>
      ))}
    </div>,
    document.body,
  );
}

