export interface PaymentsFacade {
  createCheckoutSession(args: { amountCents: number; currency: string; successUrl: string; cancelUrl: string }): Promise<{ sessionId: string; url: string }>;
  refund(chargeId: string, amountCents?: number): Promise<{ refundId: string }>;
  retrieveChargeStatus(chargeId: string): Promise<'pending' | 'succeeded' | 'failed' | 'refunded'>;
}

import type Stripe from 'stripe';

export class StripePaymentsFacade implements PaymentsFacade {
  constructor(private readonly client: Stripe) {}

  async createCheckoutSession(args: { amountCents: number; currency: string; successUrl: string; cancelUrl: string }): Promise<{ sessionId: string; url: string }> {
    const session = await this.client.checkout.sessions.create({
      mode: 'payment',
      line_items: [{ price_data: { currency: args.currency, unit_amount: args.amountCents, product_data: { name: 'Order' } }, quantity: 1 }],
      success_url: args.successUrl,
      cancel_url: args.cancelUrl,
    });
    return { sessionId: session.id, url: session.url ?? '' };
  }

  async refund(chargeId: string, amountCents?: number): Promise<{ refundId: string }> {
    const refund = await this.client.refunds.create({ charge: chargeId, amount: amountCents });
    return { refundId: refund.id };
  }

  async retrieveChargeStatus(chargeId: string): Promise<'pending' | 'succeeded' | 'failed' | 'refunded'> {
    const charge = await this.client.charges.retrieve(chargeId);
    if (charge.refunded) return 'refunded';
    return charge.status as 'pending' | 'succeeded' | 'failed';
  }
}

