export class TimeoutError extends Error { constructor(public readonly ms: number) { super(`Operation timed out after ${ms}ms`); this.name = 'TimeoutError'; } }

export function withTimeout<T>(promise: Promise<T>, ms: number, message?: string): Promise<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  const timeout = new Promise<never>((_, reject) => {
    timer = setTimeout(() => reject(message ? new Error(message) : new TimeoutError(ms)), ms);
  });
  return Promise.race([promise, timeout]).finally(() => { if (timer) clearTimeout(timer); });
}

import { createServer } from 'http';
import { Server } from 'socket.io';
import { io as createClient, Socket as ClientSocket } from 'socket.io-client';
import { AddressInfo } from 'net';

export interface TestSocketHarness { io: Server; close(): Promise<void>; connect(): Promise<ClientSocket>; }

export async function createTestHarness(attach: (io: Server) => void): Promise<TestSocketHarness> {
  const httpServer = createServer();
  const io = new Server(httpServer);
  attach(io);
  await new Promise<void>((resolve) => httpServer.listen(0, resolve));
  const port = (httpServer.address() as AddressInfo).port;
  const url = `http://localhost:${port}`;
  const clients: ClientSocket[] = [];

  return {
    io,
    async connect(): Promise<ClientSocket> {
      const client = createClient(url, { transports: ['websocket'], forceNew: true });
      await new Promise<void>((resolve, reject) => {
        client.once('connect', () => resolve());
        client.once('connect_error', reject);
      });
      clients.push(client);
      return client;
    },
    async close(): Promise<void> {
      for (const c of clients) c.disconnect();
      await new Promise<void>((resolve) => io.close(() => resolve()));
      await new Promise<void>((resolve) => httpServer.close(() => resolve()));
    },
  };
}

