const SECRET = process.env.JWT_SECRET!;

export function issueToken(userId: string, authVersion: number): string {
  return jwt.sign({ sub: userId, av: authVersion }, SECRET, { algorithm: 'HS256', expiresIn: '1h' });
}

export async function verifyToken(token: string): Promise<{ userId: string } | null> {
  let payload: { sub: string; av: number };
  try { payload = jwt.verify(token, SECRET, { algorithms: ['HS256'] }) as typeof payload; }
  catch { return null; }
  const user = await UserModel.findById(payload.sub).lean<User | null>();
  if (!user || user.authVersion !== payload.av) return null;
  return { userId: user._id };
}

