export async function runSequentially<T, R>(items: ReadonlyArray<T>, fn: (item: T, index: number) => Promise<R>): Promise<R[]> {
  const results: R[] = [];
  for (let i = 0; i < items.length; i++) {
    results.push(await fn(items[i], i));
  }
  return results;
}

export async function runSequentiallyWithFailFast<T, R>(items: ReadonlyArray<T>, fn: (item: T, index: number) => Promise<R>): Promise<{ ok: true; results: R[] } | { ok: false; completed: R[]; failedAtIndex: number; error: Error }> {
  const completed: R[] = [];
  for (let i = 0; i < items.length; i++) {
    try { completed.push(await fn(items[i], i)); }
    catch (e) { return { ok: false, completed, failedAtIndex: i, error: e instanceof Error ? e : new Error(String(e)) }; }
  }
  return { ok: true, results: completed };
}

import { EventEmitter } from 'events';

export class TypedEmitter<E extends Record<string, unknown[]>> {
  private emitter = new EventEmitter();

  on<K extends keyof E & string>(event: K, listener: (...args: E[K]) => void): this {
    this.emitter.on(event, listener as (...args: unknown[]) => void);
    return this;
  }
  off<K extends keyof E & string>(event: K, listener: (...args: E[K]) => void): this {
    this.emitter.off(event, listener as (...args: unknown[]) => void);
    return this;
  }
  once<K extends keyof E & string>(event: K, listener: (...args: E[K]) => void): this {
    this.emitter.once(event, listener as (...args: unknown[]) => void);
    return this;
  }
  emit<K extends keyof E & string>(event: K, ...args: E[K]): boolean {
    return this.emitter.emit(event, ...args);
  }
  setMaxListeners(n: number): this { this.emitter.setMaxListeners(n); return this; }
  listenerCount<K extends keyof E & string>(event: K): number { return this.emitter.listenerCount(event); }
}

