import { Request, Response, NextFunction } from 'express';
import type { Redis } from 'ioredis';

interface LimitOptions { windowMs: number; max: number; }

async function consume(redis: Redis, key: string, opts: LimitOptions): Promise<{ allowed: boolean; remaining: number; resetMs: number }> {
  const count = await redis.incr(key);
  if (count === 1) await redis.pexpire(key, opts.windowMs);
  const ttl = await redis.pttl(key);
  return { allowed: count <= opts.max, remaining: Math.max(0, opts.max - count), resetMs: ttl };
}

export function perIpLimiter(redis: Redis, opts: LimitOptions) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const ip = req.ip ?? 'unknown';
    const result = await consume(redis, `rl:ip:${ip}`, opts);
    res.setHeader('X-RateLimit-IP-Remaining', result.remaining);
    if (!result.allowed) { res.status(429).json({ error: 'IP_RATE_LIMITED' }); return; }
    next();
  };
}

export function perUserLimiter(redis: Redis, opts: LimitOptions) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const userId = (req as Request & { userId?: string }).userId;
    if (!userId) return next();
    const result = await consume(redis, `rl:user:${userId}`, opts);
    res.setHeader('X-RateLimit-User-Remaining', result.remaining);
    if (!result.allowed) { res.status(429).json({ error: 'USER_RATE_LIMITED' }); return; }
    next();
  };
}

