import { withRetry, RetryOptions } from './retry';

const IDEMPOTENT_METHODS = new Set(['GET', 'HEAD', 'PUT', 'DELETE']);

export async function fetchWithRetry(url: string, init: RequestInit & { retry?: Partial<RetryOptions> } = {}): Promise<Response> {
  const method = (init.method ?? 'GET').toUpperCase();
  const baseOpts: RetryOptions = { maxAttempts: 4, baseDelayMs: 500, maxDelayMs: 8000, retryOn: defaultRetryOn };
  const opts: RetryOptions = { ...baseOpts, ...init.retry };
  if (!IDEMPOTENT_METHODS.has(method)) opts.maxAttempts = 1;
  return withRetry(async () => {
    const res = await fetch(url, init);
    if (res.status >= 500 || res.status === 408 || res.status === 429) throw new RetryableHttpError(res.status);
    return res;
  }, opts);
}

export class RetryableHttpError extends Error { constructor(public readonly status: number) { super(`HTTP_${status}`); this.name = 'RetryableHttpError'; } }

function defaultRetryOn(err: unknown): boolean {
  if (err instanceof RetryableHttpError) return true;
  if (err instanceof TypeError) return true;
  if (err instanceof Error && err.name === 'AbortError') return false;
  return false;
}

