import { Request, Response, NextFunction, RequestHandler } from 'express';
import { ZodSchema } from 'zod';
import { ForbiddenError, NotFoundError, ValidationError } from './errors';

export function validate<T>(schema: ZodSchema<T>): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction) => {
    const parsed = schema.safeParse(req.body);
    if (!parsed.success) return next(new ValidationError('Invalid body', parsed.error.flatten()));
    (req as Request & { dto: T }).dto = parsed.data;
    next();
  };
}

export function loadEntity<T>(loader: (id: string) => Promise<T | null>): RequestHandler {
  return async (req: Request, _res: Response, next: NextFunction) => {
    const id = req.params.id;
    if (!id) return next(new NotFoundError('Missing id'));
    const entity = await loader(id);
    if (!entity) return next(new NotFoundError(`Entity ${id}`));
    (req as Request & { entity: T }).entity = entity;
    next();
  };
}

export function authorize<T>(check: (entity: T, userId: string) => boolean): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction) => {
    const entity = (req as Request & { entity: T }).entity;
    const userId = (req as Request & { userId?: string }).userId;
    if (!userId) return next(new ForbiddenError('Authentication required'));
    if (!check(entity, userId)) return next(new ForbiddenError('Not the owner'));
    next();
  };
}

