export function attachUserLookup(io: Server): void {
  io.use(async (socket: Socket, next: (err?: Error) => void) => {
    try {
      const userId = (socket.handshake.auth as { userId?: string }).userId;
      if (!userId) return next(new Error('UNAUTHENTICATED'));
      const user = await UserModel.findById(userId).lean<{ _id: string; email: string; roles: string[] } | null>();
