import { generateRegistrationOptions, verifyRegistrationResponse, GenerateRegistrationOptionsOpts, VerifyRegistrationResponseOpts } from '@simplewebauthn/server';
import type { RegistrationResponseJSON } from '@simplewebauthn/types';
import { Schema, model } from 'mongoose';

interface PasskeyCredential { _id: string; userId: string; credentialId: string; publicKey: string; counter: number; transports: string[]; createdAt: Date; }

const PasskeySchema = new Schema<PasskeyCredential>({
  userId: { type: String, required: true, index: true },
  credentialId: { type: String, required: true, unique: true },
  publicKey: { type: String, required: true },
  counter: { type: Number, default: 0 },
  transports: [String],
  createdAt: { type: Date, default: Date.now },
});
export const PasskeyModel = model<PasskeyCredential>('Passkey', PasskeySchema);

import type { Redis } from 'ioredis';

export class PasskeyService {
  constructor(private readonly redis: Redis, private readonly rpId: string, private readonly origin: string) {}

  async startRegistration(userId: string, username: string): Promise<ReturnType<typeof generateRegistrationOptions>> {
    const existing = await PasskeyModel.find({ userId }).lean<PasskeyCredential[]>();
    const opts: GenerateRegistrationOptionsOpts = {
      rpName: 'Example App',
      rpID: this.rpId,
      userName: username,
      userID: new TextEncoder().encode(userId),
      attestationType: 'none',
      excludeCredentials: existing.map((c) => ({ id: c.credentialId, transports: c.transports as ('usb' | 'nfc' | 'ble' | 'internal')[] })),
      authenticatorSelection: { residentKey: 'preferred', userVerification: 'preferred' },
    };
    const options = await generateRegistrationOptions(opts);
    await this.redis.set(`webauthn:challenge:${userId}`, options.challenge, 'EX', 300);
    return options;
  }

  async finishRegistration(userId: string, response: RegistrationResponseJSON): Promise<{ ok: boolean }> {
    const expectedChallenge = await this.redis.get(`webauthn:challenge:${userId}`);
    if (!expectedChallenge) return { ok: false };
    const verifyOpts: VerifyRegistrationResponseOpts = { response, expectedChallenge, expectedOrigin: this.origin, expectedRPID: this.rpId };
    const result = await verifyRegistrationResponse(verifyOpts);
    if (!result.verified || !result.registrationInfo) return { ok: false };
    const { credentialID, credentialPublicKey, counter } = result.registrationInfo;
    await PasskeyModel.create({
      userId,
      credentialId: Buffer.from(credentialID).toString('base64url'),
      publicKey: Buffer.from(credentialPublicKey).toString('base64'),
      counter,
      transports: response.response.transports ?? [],
    });
    await this.redis.del(`webauthn:challenge:${userId}`);
    return { ok: true };
  }
}

import { Request, Response } from 'express';
import { renderToPipeableStream } from 'react-dom/server';
