export function ssrHandler(req: Request, res: Response): void {
  let didError = false;
  const { pipe, abort } = renderToPipeableStream(
    <App url={req.url} />,
    {
      bootstrapScripts: ['/assets/client.js'],
      onShellReady() {
        res.statusCode = didError ? 500 : 200;
        res.setHeader('Content-Type', 'text/html; charset=utf-8');
        res.setHeader('Transfer-Encoding', 'chunked');
        pipe(res);
      },
      onShellError() {
        res.statusCode = 500;
        res.setHeader('Content-Type', 'text/html; charset=utf-8');
        res.send('<!doctype html><h1>Loading failed</h1>');
      },
      onAllReady() {},
      onError(err) { didError = true; console.error('[ssr]', err); },
    },
  );
  setTimeout(() => abort(), 10_000);
  req.on('close', () => abort());
}

export function assertNever(value: never): never { throw new Error(`Unhandled case: ${JSON.stringify(value)}`); }

type CasesOf<T extends { kind: string }, R> = { [K in T['kind']]: (value: Extract<T, { kind: K }>) => R };

export function match<T extends { kind: string }, R>(value: T, cases: CasesOf<T, R>): R {
  const handler = cases[value.kind as T['kind']];
  if (!handler) return assertNever(value as never);
  return handler(value as Extract<T, { kind: T['kind'] }>);
}

