import { Server } from 'socket.io';

export interface PreferenceProvider { hasMuted(userId: string, channel: string): Promise<boolean>; }

export class FilteredBroadcaster {
  constructor(private readonly io: Server, private readonly prefs: PreferenceProvider) {}

  async toRoom(roomId: string, channel: string, event: string, payload: unknown): Promise<{ delivered: number; skipped: number }> {
    const sockets = await this.io.in(roomId).fetchSockets();
    let delivered = 0, skipped = 0;
    const checks = sockets.map(async (s) => {
      const userId = (s.data as { userId?: string }).userId;
      if (!userId) return { socket: s, send: false };
      const muted = await this.prefs.hasMuted(userId, channel);
      return { socket: s, send: !muted };
    });
    const results = await Promise.all(checks);
    for (const { socket, send } of results) {
      if (send) { socket.emit(event, payload); delivered++; }
      else skipped++;
    }
    return { delivered, skipped };
  }
}

