export interface HttpRequestConfig { method: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE'; url: string; body?: unknown; headers: Record<string, string>; timeoutMs: number; }

export class HttpRequestBuilder {
  private config: Partial<HttpRequestConfig> = { headers: {}, timeoutMs: 10_000 };

  method(value: HttpRequestConfig['method']): this { this.config.method = value; return this; }
  url(value: string): this { this.config.url = value; return this; }
  body(value: unknown): this { this.config.body = value; return this; }
  header(name: string, value: string): this { this.config.headers = { ...this.config.headers, [name]: value }; return this; }
  timeout(ms: number): this { this.config.timeoutMs = ms; return this; }

  build(): HttpRequestConfig {
    if (!this.config.method) throw new Error('method required');
    if (!this.config.url) throw new Error('url required');
    if (this.config.body !== undefined && (this.config.method === 'GET' || this.config.method === 'DELETE')) {
      throw new Error(`body not allowed on ${this.config.method}`);
    }
    return this.config as HttpRequestConfig;
  }
}

import type { Redis } from 'ioredis';

export interface ChannelMap { 'cache.invalidate': { key: string }; 'config.changed': { name: string; value: string }; 'user.banned': { userId: string }; }

export class TypedPubSub<M extends Record<string, unknown> = ChannelMap> {
  private subscriptions = new Map<keyof M, Set<(payload: M[keyof M]) => void>>();
  constructor(private readonly publisher: Redis, private readonly subscriber: Redis) {
    subscriber.on('message', (channel, message) => {
      const handlers = this.subscriptions.get(channel as keyof M);
      if (!handlers) return;
      let payload: M[keyof M];
      try { payload = JSON.parse(message) as M[keyof M]; }
      catch { return; }
      handlers.forEach((h) => h(payload));
    });
  }

  async publish<K extends keyof M & string>(channel: K, payload: M[K]): Promise<void> {
    await this.publisher.publish(channel, JSON.stringify(payload));
  }

  async subscribe<K extends keyof M & string>(channel: K, handler: (payload: M[K]) => void): Promise<() => Promise<void>> {
    let handlers = this.subscriptions.get(channel) as Set<(p: M[K]) => void> | undefined;
    if (!handlers) {
      handlers = new Set();
      this.subscriptions.set(channel, handlers as Set<(p: M[keyof M]) => void>);
      await this.subscriber.subscribe(channel);
    }
    handlers.add(handler);
    return async () => {
      handlers!.delete(handler);
      if (handlers!.size === 0) {
        this.subscriptions.delete(channel);
        await this.subscriber.unsubscribe(channel);
      }
    };
  }
}

export function fromTuple<K extends ReadonlyArray<string>, V>(keys: K, value: (key: K[number]) => V): Record<K[number], V> {
  const result = {} as Record<K[number], V>;
  for (const key of keys) result[key as K[number]] = value(key as K[number]);
  return result;
}

export function strictRecord<K extends ReadonlyArray<string>>(keys: K) {
  return <V>(map: Record<K[number], V>): Record<K[number], V> => map;
}

