import { GraphQLError, parse, validate, DocumentNode, FieldNode } from 'graphql';
import type { ValidationRule } from 'graphql';

export function depthLimit(maxDepth: number): ValidationRule {
  return (ctx) => ({
    Document(doc: DocumentNode) {
      for (const def of doc.definitions) {
        if (def.kind !== 'OperationDefinition') continue;
        const depth = computeDepth(def.selectionSet);
        if (depth > maxDepth) {
          ctx.reportError(new GraphQLError(`Query exceeds maximum depth of ${maxDepth} (got ${depth})`));
        }
      }
    },
  });
}

function computeDepth(selectionSet: { selections: ReadonlyArray<{ kind: string; selectionSet?: { selections: ReadonlyArray<unknown> } }> } | undefined): number {
  if (!selectionSet) return 0;
  let max = 1;
  for (const sel of selectionSet.selections) {
    if (sel.kind === 'Field') {
      const field = sel as FieldNode;
      const childDepth = field.selectionSet ? 1 + computeDepth(field.selectionSet as { selections: ReadonlyArray<{ kind: string; selectionSet?: { selections: ReadonlyArray<unknown> } }> }) : 1;
      if (childDepth > max) max = childDepth;
    }
  }
  return max;
}

export function validateBeforeExec(schema: import('graphql').GraphQLSchema, query: string, rules: ReadonlyArray<ValidationRule>): GraphQLError[] {
  const doc = parse(query);
  return Array.from(validate(schema, doc, [...rules]));
}

