import { Server, Socket } from 'socket.io';

export function attachTransportWatcher(io: Server): void {
  io.on('connection', (socket: Socket) => {
    const transport = socket.conn.transport.name;
    if (transport === 'polling') {
      socket.emit('connection:degraded', { reason: 'WEBSOCKET_BLOCKED', currentTransport: 'polling' });
    }

    socket.conn.on('upgrade', (next) => {
      socket.emit('connection:restored', { newTransport: next.name });
    });

    socket.conn.on('upgradeError', (err: Error) => {
      socket.emit('connection:degraded', { reason: 'UPGRADE_FAILED', error: err.message });
    });
  });
}

const SAFE_DATA_PROPS = /^data-[a-z][a-z0-9-]*$/;
const SAFE_ARIA_PROPS = /^aria-[a-z][a-z0-9-]*$/;
const FORBIDDEN_PROP_PREFIXES = ['on', 'dangerouslySet'];
const SAFE_NAMED_PROPS = new Set(['id', 'className', 'title', 'role', 'tabIndex']);

export function safeAttrs(input: Record<string, unknown>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(input)) {
    if (FORBIDDEN_PROP_PREFIXES.some((p) => key.startsWith(p))) continue;
    if (SAFE_DATA_PROPS.test(key) || SAFE_ARIA_PROPS.test(key) || SAFE_NAMED_PROPS.has(key)) {
      if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') out[key] = value;
    }
  }
  return out;
}

