import { useReducer } from 'react';

interface Row { id: string; sku: string; qty: number; }
interface State { rows: Row[]; }
type Action =
  | { type: 'ADD' }
  | { type: 'REMOVE'; id: string }
  | { type: 'UPDATE'; id: string; patch: Partial<Omit<Row, 'id'>> };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'ADD': return { rows: [...state.rows, { id: crypto.randomUUID(), sku: '', qty: 1 }] };
    case 'REMOVE': return { rows: state.rows.filter((r) => r.id !== action.id) };
    case 'UPDATE': return { rows: state.rows.map((r) => (r.id === action.id ? { ...r, ...action.patch } : r)) };
  }
}

