import { z, ZodError, ZodIssue } from 'zod';

export function bestUnionMatch<T>(schema: z.ZodUnion<[z.ZodTypeAny, ...z.ZodTypeAny[]]>, input: unknown): { ok: true; value: T } | { ok: false; issues: ZodIssue[] } {
  const result = schema.safeParse(input);
  if (result.success) return { ok: true, value: result.data as T };

  let bestBranchIssues: ZodIssue[] = [];
  let bestDepth = -1;
  for (const issue of result.error.issues) {
    if (issue.code === 'invalid_union') {
      for (const branchErrors of issue.unionErrors) {
        const depth = branchErrors.issues.reduce((max, i) => Math.max(max, i.path.length), 0);
        if (depth > bestDepth) {
          bestDepth = depth;
          bestBranchIssues = branchErrors.issues;
        }
      }
    }
  }
  return { ok: false, issues: bestBranchIssues.length > 0 ? bestBranchIssues : result.error.issues };
}

import { TypedEmitter } from './typed-emitter';

export interface CoreEvents {
  'app.boot': [];
  'app.shutdown': [];
  'request.start': [{ requestId: string; path: string }];
  'request.end': [{ requestId: string; durationMs: number; status: number }];
  'error': [Error];
}

export interface PluginContext { events: TypedEmitter<CoreEvents>; log: (msg: string, ctx?: Record<string, unknown>) => void; }
export interface Plugin { name: string; register(ctx: PluginContext): Promise<void> | void; }

export class PluginHost {
  readonly events = new TypedEmitter<CoreEvents>();
  private registered: string[] = [];

  async loadAll(plugins: ReadonlyArray<Plugin>, log: (m: string, c?: Record<string, unknown>) => void): Promise<void> {
    for (const plugin of plugins) {
      if (this.registered.includes(plugin.name)) throw new Error(`DUPLICATE_PLUGIN:${plugin.name}`);
      await plugin.register({ events: this.events, log });
      this.registered.push(plugin.name);
      log('plugin.loaded', { name: plugin.name });
    }
  }
}

