import { readFile } from 'fs/promises';

export class ConfigLoader {
  private cache: { path: string; data: Record<string, unknown>; mtime: number } | null = null;

  async load(path: string): Promise<Record<string, unknown>> {
    if (this.cache && this.cache.path === path) return this.cache.data;
    const raw = await readFile(path, 'utf-8');
    const data = JSON.parse(raw) as Record<string, unknown>;
    this.cache = { path, data, mtime: Date.now() };
    return data;
  }

  invalidate(): void { this.cache = null; }
}

import { createReadStream } from 'fs';

export function readJsonStream<T>(path: string, expected: (raw: unknown) => raw is T): Promise<T> {
  return new Promise((resolve, reject) => {
    let buffer = '';
    const stream = createReadStream(path, { encoding: 'utf-8' });
    stream.on('data', (chunk) => { buffer += chunk; });
    stream.on('end', () => {
      try { const parsed: unknown = JSON.parse(buffer); if (!expected(parsed)) return reject(new Error('SHAPE_INVALID')); resolve(parsed); }
      catch (e) { reject(e); }
    });
    stream.on('error', reject);
  });
}

import { Schema, model } from 'mongoose';
import { ChangeStream, ResumeToken } from 'mongodb';

interface CursorState { _id: string; resumeToken: ResumeToken; updatedAt: Date; }

const CursorStateSchema = new Schema<CursorState>({
  _id: String,
  resumeToken: Schema.Types.Mixed,
  updatedAt: { type: Date, default: Date.now },
});
export const CursorStateModel = model<CursorState>('CursorState', CursorStateSchema);

export class PersistentChangeStream {
  private stream: ChangeStream | null = null;
  private resumeToken: ResumeToken | undefined;

  constructor(private readonly cursorName: string, private readonly openStream: (resumeAfter?: ResumeToken) => ChangeStream) {}

  async start(handler: (change: unknown) => Promise<void>): Promise<void> {
    const saved = await CursorStateModel.findById(this.cursorName).lean<CursorState | null>();
    this.resumeToken = saved?.resumeToken;
    this.stream = this.openStream(this.resumeToken);
    this.stream.on('change', async (change: { _id: ResumeToken }) => {
      try {
        await handler(change);
        this.resumeToken = change._id;
        await CursorStateModel.findByIdAndUpdate(this.cursorName, { resumeToken: change._id, updatedAt: new Date() }, { upsert: true });
      } catch (err) { console.error('[change-stream] handler error', err); }
    });
    this.stream.on('error', (err) => { console.error('[change-stream] error', err); });
  }

  async stop(): Promise<void> { await this.stream?.close(); this.stream = null; }
}

import { Socket } from 'socket.io';

interface TelemetryFrame { seq: number; ts: number; payload: unknown; }
interface SocketState { latest: TelemetryFrame | null; inFlight: boolean; dropped: number; }
const socketState = new WeakMap<Socket, SocketState>();

export function registerTelemetrySocket(socket: Socket): void {
  socketState.set(socket, { latest: null, inFlight: false, dropped: 0 });
  socket.conn.on('drain', () => flushLatest(socket));
  socket.on('disconnect', () => socketState.delete(socket));
}

export function emitTelemetry(socket: Socket, frame: TelemetryFrame): void {
  const state = socketState.get(socket);
  if (!state) return;
  state.latest = frame;
  if (state.inFlight || socket.conn.transport.writable === false) {
    state.dropped += 1;
    socket.volatile.compress(false).emit('telemetry:skipped', { latestSeq: frame.seq, dropped: state.dropped });
    return;
  }
  flushLatest(socket);
}

function flushLatest(socket: Socket): void {
  const state = socketState.get(socket);
  if (!state?.latest || socket.conn.transport.writable === false) return;
  const frame = state.latest;
  state.latest = null;
  state.inFlight = true;
  socket.volatile.compress(false).emit('telemetry:snapshot', { frame, dropped: state.dropped }, () => {
    state.inFlight = false;
    state.dropped = 0;
    if (state.latest) flushLatest(socket);
  });
}

