import { useEffect, useRef, useCallback } from 'react';

export function useAbortableFetch(): { fetch: (input: RequestInfo, init?: RequestInit) => Promise<Response>; abort: () => void } {
  const controllerRef = useRef<AbortController | null>(null);

  useEffect(() => () => { controllerRef.current?.abort(); }, []);

  const fetchFn = useCallback((input: RequestInfo, init: RequestInit = {}): Promise<Response> => {
    controllerRef.current?.abort();
    controllerRef.current = new AbortController();
    return fetch(input, { ...init, signal: controllerRef.current.signal });
  }, []);

  const abort = useCallback(() => controllerRef.current?.abort(), []);

  return { fetch: fetchFn, abort };
}

