import { config as dotenvConfig } from 'dotenv';
import { z } from 'zod';

const EnvSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'staging', 'production']),
  PORT: z.coerce.number().int().min(1).max(65535).default(3000),
  DATABASE_URL: z.string().url(),
  JWT_SECRET: z.string().min(32),
  STRIPE_SECRET: z.string().startsWith('sk_'),
  SENTRY_DSN: z.string().url().optional(),
});

export type AppEnv = z.infer<typeof EnvSchema>;

export function loadEnv(): AppEnv {
  if (process.env.NODE_ENV !== 'production') {
    dotenvConfig({ path: process.env.ENV_FILE ?? '.env' });
  }
  const parsed = EnvSchema.safeParse(process.env);
  if (!parsed.success) {
    const flat = parsed.error.flatten().fieldErrors;
    const missing = Object.entries(flat).map(([k, v]) => `  - ${k}: ${(v ?? []).join('; ')}`).join('\n');
    throw new Error(`Invalid environment:\n${missing}`);
  }
  return parsed.data;
}

import { Request, Response, NextFunction, RequestHandler } from 'express';
import { ConflictError, NotFoundError } from './errors';
import { UserModel } from './user.model';

export const asyncHandler = (fn: (req: Request, res: Response, next: NextFunction) => Promise<unknown>): RequestHandler =>
  (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);

export const createUser = asyncHandler(async (req: Request, res: Response): Promise<void> => {
  const { email, name } = req.body as { email: string; name: string };
  const existing = await UserModel.findOne({ email: email.toLowerCase() }).lean();
  if (existing) throw new ConflictError('Email already in use');
  const user = await UserModel.create({ email: email.toLowerCase(), name });
  res.status(201).json({ id: String(user._id) });
});

export const deleteUser = asyncHandler(async (req: Request, res: Response): Promise<void> => {
  const result = await UserModel.deleteOne({ _id: req.params.id });
  if (result.deletedCount === 0) throw new NotFoundError('User');
  res.status(204).end();
});

