import { Request, Response } from 'express';
import { pipeline } from 'stream/promises';
import { Writable } from 'stream';
import { parse } from 'csv-parse';
import { Model } from 'mongoose';

export function createCsvImporter<T>(model: Model<T>, transform: (row: Record<string, string>) => Partial<T>, batchSize = 1000) {
  return async (req: Request, res: Response): Promise<void> => {
    let imported = 0;
    let batch: Array<Partial<T>> = [];

    const writer = new Writable({
      objectMode: true,
      async write(row: Record<string, string>, _enc, cb): Promise<void> {
        try {
          batch.push(transform(row));
          if (batch.length >= batchSize) {
            const toFlush = batch;
            batch = [];
            await model.insertMany(toFlush, { ordered: false });
            imported += toFlush.length;
          }
          cb();
        } catch (e) { cb(e as Error); }
      },
      async final(cb): Promise<void> {
        try {
          if (batch.length > 0) { await model.insertMany(batch, { ordered: false }); imported += batch.length; batch = []; }
          cb();
        } catch (e) { cb(e as Error); }
      },
    });

    try {
      await pipeline(req, parse({ columns: true, skip_empty_lines: true, trim: true }), writer);
      res.json({ ok: true, imported });
    } catch (err) {
      res.status(400).json({ error: 'IMPORT_FAILED', message: (err as Error).message, imported });
    }
  };
}

