import crypto from 'crypto';

export interface KmsClient { encryptKey(plaintextKey: Buffer): Promise<Buffer>; decryptKey(encryptedKey: Buffer): Promise<Buffer>; }

export interface EnvelopeCiphertext { v: 1; encryptedKey: string; iv: string; ct: string; tag: string; }

export class EnvelopeCipher {
  constructor(private readonly kms: KmsClient) {}

  async encrypt(plaintext: Buffer): Promise<EnvelopeCiphertext> {
    const dataKey = crypto.randomBytes(32);
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', dataKey, iv);
    const ct = Buffer.concat([cipher.update(plaintext), cipher.final()]);
    const tag = cipher.getAuthTag();
    const encryptedKey = await this.kms.encryptKey(dataKey);
    dataKey.fill(0);
    return { v: 1, encryptedKey: encryptedKey.toString('base64'), iv: iv.toString('base64'), ct: ct.toString('base64'), tag: tag.toString('base64') };
  }

  async decrypt(env: EnvelopeCiphertext): Promise<Buffer> {
    const dataKey = await this.kms.decryptKey(Buffer.from(env.encryptedKey, 'base64'));
    try {
      const decipher = crypto.createDecipheriv('aes-256-gcm', dataKey, Buffer.from(env.iv, 'base64'));
      decipher.setAuthTag(Buffer.from(env.tag, 'base64'));
      return Buffer.concat([decipher.update(Buffer.from(env.ct, 'base64')), decipher.final()]);
    } finally { dataKey.fill(0); }
  }
}

import { createContext, useContext, useState, useCallback, ReactNode } from 'react';

interface TabsContextValue { activeTab: string; setActiveTab: (id: string) => void; }
const TabsContext = createContext<TabsContextValue | null>(null);
function useTabs(): TabsContextValue { const ctx = useContext(TabsContext); if (!ctx) throw new Error('Tabs sub-component used outside <Tabs.Root>'); return ctx; }

function Root({ defaultTab, children, onChange }: { defaultTab: string; children: ReactNode; onChange?: (id: string) => void }): JSX.Element {
  const [activeTab, setActive] = useState(defaultTab);
  const setActiveTab = useCallback((id: string) => { setActive(id); onChange?.(id); }, [onChange]);
  return <TabsContext.Provider value={{ activeTab, setActiveTab }}>{children}</TabsContext.Provider>;
}

function List({ children }: { children: ReactNode }): JSX.Element {
  return <div role="tablist" className="flex border-b">{children}</div>;
}

function Trigger({ id, children }: { id: string; children: ReactNode }): JSX.Element {
  const { activeTab, setActiveTab } = useTabs();
  const isActive = activeTab === id;
  return (
    <button role="tab" aria-selected={isActive} className={`px-4 py-2 ${isActive ? 'border-b-2 border-blue-600' : 'text-gray-600'}`} onClick={() => setActiveTab(id)}>
      {children}
    </button>
  );
}

function Panel({ id, children }: { id: string; children: ReactNode }): JSX.Element | null {
  const { activeTab } = useTabs();
  if (activeTab !== id) return null;
  return <div role="tabpanel" className="p-4">{children}</div>;
}

export const Tabs = { Root, List, Trigger, Panel };

import { Hub, captureException, withScope } from '@sentry/node';

export interface ErrorContext { module?: string; operation?: string; userId?: string; }

export function reportError(error: unknown, context: ErrorContext = {}): void {
  const err = error instanceof Error ? error : new Error(String(error));
  withScope((scope) => {
    if (context.module) scope.setTag('module', context.module);
    if (context.operation) scope.setTag('operation', context.operation);
    if (context.userId) scope.setUser({ id: context.userId });
    const fingerprint = computeFingerprint(err, context);
    scope.setFingerprint(fingerprint);
    captureException(err);
  });
}

function computeFingerprint(err: Error, ctx: ErrorContext): string[] {
  const parts = [err.name];
  if (ctx.module) parts.push(ctx.module);
  if (ctx.operation) parts.push(ctx.operation);
  const normalizedMessage = err.message
    .replace(/[0-9a-f]{8,}/gi, '[ID]')
    .replace(/\d+/g, '[N]')
    .replace(/\b\d+\.\d+\.\d+\.\d+\b/g, '[IP]')
    .slice(0, 100);
  parts.push(normalizedMessage);
  return parts;
}

