import { Schema, model, Types, FilterQuery } from 'mongoose';

interface Post { _id: Types.ObjectId; title: string; likes: number; createdAt: Date; }

const PostSchema = new Schema<Post>({
  title: String,
  likes: { type: Number, default: 0 },
  createdAt: { type: Date, default: Date.now },
});
PostSchema.index({ likes: -1, _id: 1 });
export const PostModel = model<Post>('Post', PostSchema);

export interface Cursor { likes: number; id: string; }

export async function listByLikes(limit: number, cursor?: Cursor): Promise<{ items: Post[]; nextCursor: Cursor | null }> {
  const filter: FilterQuery<Post> = {};
  if (cursor) {
    filter.$or = [
      { likes: { $lt: cursor.likes } },
      { likes: cursor.likes, _id: { $gt: new Types.ObjectId(cursor.id) } },
    ];
  }
  const items = await PostModel.find(filter).sort({ likes: -1, _id: 1 }).limit(limit).lean<Post[]>();
  const last = items[items.length - 1];
  const nextCursor = items.length === limit ? { likes: last.likes, id: last._id.toString() } : null;
  return { items, nextCursor };
}

export function notNullish<T>(value: T | null | undefined): value is T {
  return value !== null && value !== undefined;
}

export function isOfKind<T extends { kind: string }, K extends T['kind']>(kind: K): (value: T) => value is Extract<T, { kind: K }> {
  return (value): value is Extract<T, { kind: K }> => value.kind === kind;
}

type Notification = { kind: 'email'; to: string } | { kind: 'sms'; to: string } | { kind: 'push'; deviceId: string };

export function emailRecipients(items: ReadonlyArray<Notification | null>): string[] {
  return items.filter(notNullish).filter(isOfKind<Notification, 'email'>('email')).map((n) => n.to);
}

