import { Server, Socket } from 'socket.io';
import type { Redis } from 'ioredis';

export function connectionRateLimit(io: Server, redis: Redis, limitPerMin: number): void {
  io.use(async (socket: Socket, next: (err?: Error) => void) => {
    const ip = socket.handshake.address;
    const key = `conn-rate:${ip}`;
    const count = await redis.incr(key);
    if (count === 1) await redis.expire(key, 60);
    if (count > limitPerMin) {
      next(new Error('TOO_MANY_CONNECTIONS'));
      return;
    }
    next();
  });
}

declare global { interface Window { trustedTypes?: { createPolicy(name: string, rules: { createHTML: (input: string) => string; createScriptURL?: (url: string) => string }): { createHTML(input: string): string; createScriptURL(url: string): string }; }; } }

import DOMPurify from 'dompurify';

let sanitizingPolicy: { createHTML(input: string): string; createScriptURL(url: string): string } | null = null;

export function initTrustedTypes(): void {
  if (typeof window === 'undefined' || !window.trustedTypes) return;
  sanitizingPolicy = window.trustedTypes.createPolicy('app#sanitized', {
    createHTML: (input: string): string => DOMPurify.sanitize(input),
    createScriptURL: (url: string): string => {
      const parsed = new URL(url, window.location.origin);
      if (parsed.origin !== window.location.origin && parsed.origin !== 'https://cdn.example.com') throw new Error('URL_NOT_ALLOWED');
      return parsed.toString();
    },
  });
}

export function safeInnerHTML(node: Element, html: string): void {
  if (sanitizingPolicy) {
    (node as Element & { innerHTML: unknown }).innerHTML = sanitizingPolicy.createHTML(html);
  } else {
    node.innerHTML = DOMPurify.sanitize(html);
  }
}

import { useState, DragEvent } from 'react';

export interface DragItem { id: string; label: string; }

export function DraggableList({ initialItems }: { initialItems: ReadonlyArray<DragItem> }): JSX.Element {
  const [items, setItems] = useState<DragItem[]>([...initialItems]);
  const [draggedId, setDraggedId] = useState<string | null>(null);

  const onDragStart = (id: string) => (e: DragEvent<HTMLLIElement>): void => {
    setDraggedId(id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const onDragOver = (overId: string) => (e: DragEvent<HTMLLIElement>): void => {
    e.preventDefault();
    if (!draggedId || draggedId === overId) return;
    setItems((prev) => {
      const draggedIdx = prev.findIndex((i) => i.id === draggedId);
      const overIdx = prev.findIndex((i) => i.id === overId);
      if (draggedIdx < 0 || overIdx < 0) return prev;
      const next = [...prev];
      const [moved] = next.splice(draggedIdx, 1);
      next.splice(overIdx, 0, moved);
      return next;
    });
  };

  const onDragEnd = (): void => setDraggedId(null);

  return (
    <ul className="space-y-1">
      {items.map((item) => (
        <li key={item.id} draggable onDragStart={onDragStart(item.id)} onDragOver={onDragOver(item.id)} onDragEnd={onDragEnd} className={`p-2 border rounded cursor-move ${draggedId === item.id ? 'opacity-50' : ''}`}>
          {item.label}
        </li>
      ))}
    </ul>
  );
}

import { Response } from 'express';

export function sendJsonOnce(res: Response, status: number, body: unknown): boolean {
  if (res.headersSent) {
    console.warn('[response] attempted second send', { status, currentStatus: res.statusCode });
    return false;
  }
  res.status(status).json(body);
  return true;
}

export class SafeResponder {
  constructor(private readonly res: Response) {}
  json(status: number, body: unknown): boolean { return sendJsonOnce(this.res, status, body); }
  noContent(): boolean { return sendJsonOnce(this.res, 204, undefined); }
}

export class CurrencyMismatchError extends Error { constructor(public readonly a: string, public readonly b: string) { super(`Currency mismatch: ${a} vs ${b}`); } }

export class Money {
  constructor(public readonly amountMinor: number, public readonly currency: string) {
    if (!Number.isInteger(amountMinor)) throw new Error('AMOUNT_NOT_INTEGER');
    if (!/^[A-Z]{3}$/.test(currency)) throw new Error('INVALID_CURRENCY');
  }

  static zero(currency: string): Money { return new Money(0, currency); }

  add(other: Money): Money {
    if (this.currency !== other.currency) throw new CurrencyMismatchError(this.currency, other.currency);
    return new Money(this.amountMinor + other.amountMinor, this.currency);
  }

  subtract(other: Money): Money {
    if (this.currency !== other.currency) throw new CurrencyMismatchError(this.currency, other.currency);
    return new Money(this.amountMinor - other.amountMinor, this.currency);
  }

  multiply(factor: number): Money { return new Money(Math.round(this.amountMinor * factor), this.currency); }

  equals(other: Money): boolean { return this.amountMinor === other.amountMinor && this.currency === other.currency; }

  toString(): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: this.currency }).format(this.amountMinor / 100);
  }
}

