# TS-side: monitor RSS so the operational fix can be measured.
import v8 from 'v8';

export interface MemorySnapshot { rssMB: number; heapUsedMB: number; heapTotalMB: number; externalMB: number; arrayBuffersMB: number; ts: string; }

export function captureMemorySnapshot(): MemorySnapshot {
  const mem = process.memoryUsage();
  return {
    rssMB: Math.round(mem.rss / 1024 / 1024),
    heapUsedMB: Math.round(mem.heapUsed / 1024 / 1024),
    heapTotalMB: Math.round(mem.heapTotal / 1024 / 1024),
    externalMB: Math.round(mem.external / 1024 / 1024),
    arrayBuffersMB: Math.round(mem.arrayBuffers / 1024 / 1024),
    ts: new Date().toISOString(),
  };
}

export function emitMemoryMetrics(intervalMs: number, sink: (m: MemorySnapshot) => void): () => void {
  const interval = setInterval(() => sink(captureMemorySnapshot()), intervalMs).unref();
  return () => clearInterval(interval);
}

export function getHeapStatistics(): v8.HeapInfo { return v8.getHeapStatistics(); }

import { ConflictError, NotFoundError } from '../errors';
import { Model, Types } from 'mongoose';

export async function updateWithRetry<T extends { _id: Types.ObjectId; __v?: number }>(
  model: Model<T>,
  id: string,
  patcher: (current: T) => Partial<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    const current = await model.findById(id).lean<T | null>();
    if (!current) throw new NotFoundError(`Document ${id}`);
    const patch = patcher(current);
    const result = await model.findOneAndUpdate(
      { _id: current._id, __v: current.__v },
      { $set: patch, $inc: { __v: 1 } },
      { new: true, lean: true },
    );
    if (result) return result;
    await new Promise((r) => setTimeout(r, 10 * 2 ** attempt + Math.random() * 10));
  }
  throw new ConflictError(`Document ${id} could not be updated after ${maxAttempts} attempts`);
}

export function parseAnyJson(raw: string): unknown {
  return JSON.parse(raw);
}

export function isStringArray(value: unknown): value is string[] {
  return Array.isArray(value) && value.every((v) => typeof v === 'string');
}

export function isRecord(value: unknown): value is Record<string, unknown> {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

export function safeReadName(input: unknown): string | null {
  if (!isRecord(input)) return null;
  const name = input.name;
  return typeof name === 'string' ? name : null;
}

