import { createServer } from 'http';
import { Server } from 'socket.io';

interface SocketData { userId: string; sessionId: string; locale: 'en' | 'es' | 'he'; }

export function buildIO(port: number): Server<Record<string, never>, Record<string, never>, Record<string, never>, SocketData> {
  const httpServer = createServer();
  const io = new Server<Record<string, never>, Record<string, never>, Record<string, never>, SocketData>(httpServer);

  io.use((socket, next) => {
    socket.data.userId = 'u_demo';
    socket.data.sessionId = 's_demo';
    socket.data.locale = 'en';
    next();
  });

  io.on('connection', (socket) => {
    console.log(`Connected: ${socket.data.userId} (${socket.data.locale})`);
  });

  httpServer.listen(port);
  return io;
}

import crypto from 'crypto';

export interface SigningKeys { v1: string; v2: string; }

export function signPayload(payload: string, ts: number, keys: SigningKeys): { 'X-Signature-V1': string; 'X-Signature-V2': string; 'X-Timestamp': string } {
  const v1Sig = crypto.createHmac('sha1', keys.v1).update(`${ts}.${payload}`).digest('hex');
  const v2Sig = crypto.createHmac('sha256', keys.v2).update(`${ts}.${payload}`).digest('hex');
  return { 'X-Signature-V1': v1Sig, 'X-Signature-V2': v2Sig, 'X-Timestamp': String(ts) };
}

export function verifySignature(payload: string, headers: Record<string, string>, keys: SigningKeys, requireV2 = false): boolean {
  const ts = headers['x-timestamp'];
  if (!ts) return false;
  if (Math.abs(Date.now() / 1000 - Number(ts)) > 300) return false;

  const sigV2 = headers['x-signature-v2'];
  if (sigV2) {
    const expected = crypto.createHmac('sha256', keys.v2).update(`${ts}.${payload}`).digest('hex');
    return safeEqual(expected, sigV2);
  }
  if (requireV2) return false;
  const sigV1 = headers['x-signature-v1'];
  if (!sigV1) return false;
  const expectedV1 = crypto.createHmac('sha1', keys.v1).update(`${ts}.${payload}`).digest('hex');
  return safeEqual(expectedV1, sigV1);
}

function safeEqual(a: string, b: string): boolean {
  const aBuf = Buffer.from(a, 'hex');
  const bBuf = Buffer.from(b, 'hex');
  return aBuf.length === bBuf.length && crypto.timingSafeEqual(aBuf, bBuf);
}

// Targets react-window v1.x APIs; pin react-window@1.x or migrate to v2 List/Grid before copy-pasting.
import { useRef, useState, useCallback } from 'react';
import { FixedSizeList, ListChildComponentProps } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';

export interface Item { id: string; date: string; text: string; }

function monthOf(iso: string): string { return iso.slice(0, 7); }

type Row = { kind: 'header'; key: string; label: string } | { kind: 'item'; key: string; item: Item };

export function GroupedList({ items }: { items: ReadonlyArray<Item> }): JSX.Element {
  const rows = useFlattenedRows(items);
  const listRef = useRef<FixedSizeList>(null);
  const [stickyLabel, setStickyLabel] = useState<string>(rows.find((r) => r.kind === 'header')?.label ?? '');

  const onScroll = useCallback(({ scrollOffset }: { scrollOffset: number }): void => {
    const itemHeight = 40;
    const visibleIndex = Math.floor(scrollOffset / itemHeight);
    let label = '';
    for (let i = 0; i <= visibleIndex && i < rows.length; i++) {
      if (rows[i].kind === 'header') label = rows[i].label;
    }
    setStickyLabel(label);
  }, [rows]);

  const Row = ({ index, style }: ListChildComponentProps): JSX.Element => {
    const row = rows[index];
    if (row.kind === 'header') return <div style={style} className="px-4 py-2 font-semibold bg-gray-100">{row.label}</div>;
    return <div style={style} className="px-4 py-2 border-b">{row.item.text}</div>;
  };

  return (
    <div className="relative">
      <div className="sticky top-0 z-10 px-4 py-2 font-semibold bg-blue-50 border-b">{stickyLabel}</div>
      <AutoSizer>{({ width, height }) => (
        <FixedSizeList ref={listRef} height={height} width={width} itemSize={40} itemCount={rows.length} onScroll={onScroll}>{Row}</FixedSizeList>
      )}</AutoSizer>
    </div>
  );
}

function useFlattenedRows(items: ReadonlyArray<Item>): Row[] {
  const rows: Row[] = [];
  let lastMonth: string | null = null;
  for (const item of items) {
    const month = monthOf(item.date);
    if (month !== lastMonth) { rows.push({ kind: 'header', key: `h-${month}`, label: month }); lastMonth = month; }
    rows.push({ kind: 'item', key: item.id, item });
  }
  return rows;
}

import { withTimeout } from './timeout';

export type CallResult<T> = { ok: true; value: T } | { ok: false; error: string };

export async function callAllWithTimeout<T>(calls: ReadonlyArray<() => Promise<T>>, timeoutMs: number): Promise<CallResult<T>[]> {
  const wrapped = calls.map(async (call): Promise<CallResult<T>> => {
    try { const value = await withTimeout(call(), timeoutMs); return { ok: true, value }; }
    catch (e) { return { ok: false, error: e instanceof Error ? e.message : String(e) }; }
  });
  return Promise.all(wrapped);
}

import { createContext, useContext, ReactNode } from 'react';
import type { Socket } from 'socket.io-client';
import { getSocket } from './socket-singleton';

const SocketContext = createContext<Socket | null>(null);

export function SocketProvider({ children, socket = getSocket() }: { children: ReactNode; socket?: Socket }): JSX.Element {
  return <SocketContext.Provider value={socket}>{children}</SocketContext.Provider>;
}

export function useAppSocket(): Socket {
  const socket = useContext(SocketContext);
  if (!socket) throw new Error('useAppSocket called outside SocketProvider');
  return socket;
}

import jwt from 'jsonwebtoken';
import crypto from 'crypto';
import { Request, Response } from 'express';

interface TokenPair { accessToken: string; refreshToken: string; refreshJti: string; }

const SECRET = process.env.JWT_SECRET!;
const ACCESS_TTL = '5m';
const REFRESH_TTL = '30d';

export function issuePair(userId: string): TokenPair {
  const refreshJti = crypto.randomBytes(16).toString('hex');
  return {
    accessToken: jwt.sign({ sub: userId, type: 'access' }, SECRET, { algorithm: 'HS256', expiresIn: ACCESS_TTL }),
    refreshToken: jwt.sign({ sub: userId, jti: refreshJti, type: 'refresh' }, SECRET, { algorithm: 'HS256', expiresIn: REFRESH_TTL }),
    refreshJti,
  };
}

export function setRefreshCookie(res: Response, refreshToken: string): void {
  res.cookie('refresh_token', refreshToken, { httpOnly: true, secure: true, sameSite: 'strict', path: '/auth', maxAge: 30 * 24 * 3600 * 1000 });
}

export interface RefreshStore { isValid(jti: string): Promise<boolean>; invalidate(jti: string): Promise<void>; }

export async function refreshHandler(req: Request, res: Response, store: RefreshStore): Promise<void> {
  const token = (req.cookies as { refresh_token?: string }).refresh_token;
  if (!token) { res.status(401).json({ error: 'NO_REFRESH' }); return; }
  let payload: { sub: string; jti: string; type: string };
  try { payload = jwt.verify(token, SECRET, { algorithms: ['HS256'] }) as typeof payload; }
  catch { res.status(401).json({ error: 'INVALID' }); return; }
  if (payload.type !== 'refresh') { res.status(401).json({ error: 'WRONG_TYPE' }); return; }
  if (!await store.isValid(payload.jti)) { res.status(401).json({ error: 'REUSED' }); return; }
  await store.invalidate(payload.jti);
  const pair = issuePair(payload.sub);
  setRefreshCookie(res, pair.refreshToken);
  res.json({ accessToken: pair.accessToken });
}

import { useEffect, useRef, useState } from 'react';

export interface KeyedResource<T> { key: string | null; data: T | null; loading: boolean; error: Error | null; }

export function useKeyedResource<T>(key: string | null, fetcher: (key: string, signal: AbortSignal) => Promise<T>): KeyedResource<T> {
  const [state, setState] = useState<KeyedResource<T>>({ key, data: null, loading: false, error: null });
  const genRef = useRef(0);

  useEffect(() => {
    if (key === null) { setState({ key: null, data: null, loading: false, error: null }); return; }
    const gen = ++genRef.current;
    const controller = new AbortController();
    setState((s) => ({ ...s, key, loading: true, error: null }));
    fetcher(key, controller.signal).then(
      (data) => { if (gen === genRef.current) setState({ key, data, loading: false, error: null }); },
      (err: unknown) => {
        if (gen !== genRef.current) return;
        if (err instanceof DOMException && err.name === 'AbortError') return;
        setState({ key, data: null, loading: false, error: err instanceof Error ? err : new Error(String(err)) });
      },
    );
    return () => controller.abort();
  }, [key, fetcher]);

  return state;
}

import { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import { errorMiddleware } from './errors';

export function ultimateFallback(inner: ErrorRequestHandler): ErrorRequestHandler {
  return (err: unknown, req: Request, res: Response, next: NextFunction): void => {
    try { return inner(err, req, res, next); }
    catch (handlerErr) {
      console.error('[error-middleware] failed handling error', { handlerErr, originalErr: err });
      if (res.headersSent) return;
      try { res.status(500).json({ error: { code: 'INTERNAL_HANDLER_FAILED' } }); }
      catch { res.end(); }
    }
  };
}

